+import type {
+  ExtensionAPI,
+  ToolDefinition,
+} from "@mariozechner/pi-coding-agent";
+import {
+  buildAgentsPrompt,
+  discoverAgents,
+  formatAgentList,
+  resolveAgentByName,
+  type Scope,
+} from "../catalog/agents.js";
+import { toDiagnosticText } from "../catalog/diagnostics.js";
+import { DelegatedAgentRunError } from "../engine/subprocess.js";
+import { RunExecutionError } from "../runtime/executor.js";
+import type {
+  AgentRunDetails,
+  RunResultDetails,
+  WorkflowParams,
+} from "../runtime/types.js";
+import {
+  AgentParamsSchema,
+  type ToolPromptMetadata,
+  UnknownAgentError,
+  WorkflowParamsSchema,
+} from "../tools/definitions.js";
+import {
