+      reloadRunState(ctx);
+    });
+    pi.on("session_fork", async (_event, ctx) => {
+      reloadRunState(ctx);
+    });
+    pi.on("session_tree", async (_event, ctx) => {
+      reloadRunState(ctx);
+    });
